import type {
  AdapterCapabilities,
  AdapterCategory,
  AdapterSubscription,
  ConnectionStatus,
  ExchangeAdapter,
  ExchangeConfig,
  HealthMetrics,
  OHLCVCallback,
  OrderbookCallback,
  StatusCallback,
  TickerCallback,
  TradeCallback,
} from '../../types/adapter';
import type { NormalizedOHLCV, NormalizedOrderbook, NormalizedSymbol, NormalizedTrade, Timeframe } from '../../types/normalized';
import { createSubscriptionId, secondsToMs } from '../../normalization/pipeline';
import { RateLimiter, EXCHANGE_RATE_LIMITS } from '../../rate-limiter/rate-limiter';
import type { BirdeyeOHLCV, BirdeyeResponse, BirdeyeTrade, BirdeyeTimeType } from './raydium-types';

const DEFAULT_SOLANA_WS_URL = 'wss://api.mainnet-beta.solana.com';
const DEFAULT_BIRDEYE_API_URL = 'https://public-api.birdeye.so';

/** Default polling interval (5 seconds). */
const DEFAULT_POLL_INTERVAL_MS = 5_000;

/** Timeframe to Birdeye time type mapping. */
const TIME_TYPE_MAP: Partial<Record<Timeframe, BirdeyeTimeType>> = {
  '1m': '1m', '3m': '3m', '5m': '5m', '15m': '15m', '30m': '30m',
  '1h': '1H', '2h': '2H', '4h': '4H', '6h': '6H', '12h': '12H',
  '1d': '1D', '1w': '1W',
};

interface ActiveSubscription {
  readonly id: string;
  readonly symbol: string;
  readonly tokenAddress: string;
  readonly type: 'ticker' | 'orderbook' | 'trades' | 'ohlcv' | 'status';
  readonly callback: TickerCallback | OrderbookCallback | TradeCallback | OHLCVCallback | StatusCallback;
}

/**
 * Raydium DEX adapter using Birdeye API for historical data
 * and Solana RPC for real-time updates.
 *
 * Limitations:
 * - Public Solana RPC: 100 req/10s, 40 WS subscriptions
 * - Birdeye free tier: 100 req/min
 * - Solana WebSocket connections are unreliable
 */
export class RaydiumAdapter implements ExchangeAdapter {
  readonly exchangeId = 'raydium' as const;
  readonly displayName = 'Raydium';
  readonly category: AdapterCategory = 'dex';
  readonly capabilities: AdapterCapabilities = {
    realtime: true,
    historicalDepth: '30d',
    orderbook: false,
    trades: true,
    ohlcv: true,
    fundingRates: false,
    openInterest: false,
    liquidations: false,
    defiMetrics: true,
    onChainMetrics: true,
    authenticated: false,
  };

  private config: ExchangeConfig | null = null;
  private birdeyeApiUrl = DEFAULT_BIRDEYE_API_URL;
  private birdeyeApiKey = '';
  private rateLimiter: RateLimiter | null = null;
  private readonly subscriptions = new Map<string, ActiveSubscription>();
  private readonly statusCallbacks = new Map<string, StatusCallback>();
  private pollTimer: ReturnType<typeof setInterval> | undefined;
  private connectionState: ConnectionStatus = {
    state: 'disconnected',
    latencyMs: 0,
    messagesPerSecond: 0,
    lastMessageAt: 0,
    reconnectAttempt: 0,
    uptime: 0,
  };
  private connectTime = 0;

  async connect(config: ExchangeConfig): Promise<void> {
    this.config = config;
    if (config.restUrl) {
      this.birdeyeApiUrl = config.restUrl;
    }
    if (config.apiKey) {
      this.birdeyeApiKey = config.apiKey;
    }
    const rateLimitConfig = EXCHANGE_RATE_LIMITS['raydium'];
    if (rateLimitConfig) {
      this.rateLimiter = new RateLimiter('raydium', rateLimitConfig);
    }
    this.connectTime = Date.now();
    this.updateState('connected');

    this.pollTimer = setInterval(() => {
      this.pollSubscriptions().catch(() => {
        // Polling errors are non-fatal
      });
    }, DEFAULT_POLL_INTERVAL_MS);
  }

  async disconnect(): Promise<void> {
    if (this.pollTimer !== undefined) {
      clearInterval(this.pollTimer);
      this.pollTimer = undefined;
    }
    this.subscriptions.clear();
    this.statusCallbacks.clear();
    this.rateLimiter?.dispose();
    this.rateLimiter = null;
    this.updateState('disconnected');
  }

  getStatus(): ConnectionStatus {
    return { ...this.connectionState, uptime: this.getUptime() };
  }

  getHealthMetrics(): HealthMetrics {
    const status = this.getStatus();
    const uptimeSeconds = status.uptime;
    const uptimePercent = uptimeSeconds > 0 ? Math.min(100, (uptimeSeconds / uptimeSeconds) * 100) : 0;
    return {
      connected: status.state === 'connected',
      latencyMs: status.latencyMs,
      messagesPerSecond: status.messagesPerSecond,
      uptimePercent,
      lastMessageAt: status.lastMessageAt,
      errorRate: 0,
      circuitBreakerState: 'closed',
    };
  }

  onStatusChange(callback: StatusCallback): AdapterSubscription {
    const id = createSubscriptionId('raydium', 'status', '_global');
    this.statusCallbacks.set(id, callback);
    return {
      id,
      symbol: '_global',
      type: 'status',
      dispose: () => { this.statusCallbacks.delete(id); },
    };
  }

  subscribeTicker(symbol: string, callback: TickerCallback): AdapterSubscription {
    return this.addSubscription(symbol, 'ticker', callback);
  }

  subscribeOrderbook(symbol: string, _depth: number, callback: OrderbookCallback): AdapterSubscription {
    return this.addSubscription(symbol, 'orderbook', callback);
  }

  subscribeTrades(symbol: string, callback: TradeCallback): AdapterSubscription {
    return this.addSubscription(symbol, 'trades', callback);
  }

  subscribeOHLCV(symbol: string, _timeframe: Timeframe, callback: OHLCVCallback): AdapterSubscription {
    return this.addSubscription(symbol, 'ohlcv', callback);
  }

  async getCandles(symbol: string, timeframe: Timeframe, from: number, to: number): Promise<NormalizedOHLCV[]> {
    const tokenAddress = this.extractTokenAddress(symbol);
    const timeType = TIME_TYPE_MAP[timeframe];
    if (!timeType) {
      throw new Error(`Unsupported timeframe for Raydium: ${timeframe}`);
    }
    const fromSec = Math.floor(from / 1000);
    const toSec = Math.floor(to / 1000);
    const url = `${this.birdeyeApiUrl}/defi/ohlcv?address=${tokenAddress}&type=${timeType}&time_from=${fromSec}&time_to=${toSec}`;

    await this.rateLimiter?.acquire();
    const response = await this.fetchBirdeye<{ items: BirdeyeOHLCV[] }>(url);

    return response.data.items.map(item => ({
      timestamp: secondsToMs(item.unixTime),
      open: item.o,
      high: item.h,
      low: item.l,
      close: item.c,
      volume: item.v,
      quoteVolume: item.v,
      tradeCount: 0,
      closed: true,
    }));
  }

  async getOrderbookSnapshot(_symbol: string, _depth: number): Promise<NormalizedOrderbook> {
    throw new Error('Order book not available for Raydium AMM pools');
  }

  async getRecentTrades(symbol: string, limit: number): Promise<NormalizedTrade[]> {
    const tokenAddress = this.extractTokenAddress(symbol);
    const url = `${this.birdeyeApiUrl}/defi/txs/pair?address=${tokenAddress}&limit=${Math.min(limit, 50)}`;

    await this.rateLimiter?.acquire();
    const response = await this.fetchBirdeye<{ items: BirdeyeTrade[] }>(url);

    return response.data.items.map(t => ({
      id: t.txHash,
      timestamp: secondsToMs(t.blockUnixTime),
      price: t.priceUsd,
      quantity: t.amount,
      side: t.side,
      buyerMaker: t.side === 'sell',
    }));
  }

  async getSymbols(): Promise<NormalizedSymbol[]> {
    // Raydium symbol discovery via Birdeye token list or Raydium API
    // Returns a limited set of popular pools
    const url = `${this.birdeyeApiUrl}/defi/tokenlist?sort_by=v24hUSD&sort_type=desc&limit=100`;

    await this.rateLimiter?.acquire();
    const response = await this.fetchBirdeye<{
      tokens: Array<{
        address: string;
        symbol: string;
        name: string;
        decimals: number;
        liquidity: number;
        v24hUSD: number;
      }>;
    }>(url);

    return response.data.tokens.map(token => ({
      symbol: `${token.symbol}/USDC`,
      base: token.symbol,
      quote: 'USDC',
      exchangeSymbol: token.address,
      exchangeId: 'raydium' as const,
      type: 'dex-pool' as const,
      pricePrecision: token.decimals,
      quantityPrecision: token.decimals,
      minQuantity: 0,
      tickSize: 10 ** -token.decimals,
      active: token.liquidity > 0,
      contractAddress: token.address,
      chain: 'solana',
    }));
  }

  private addSubscription(
    symbol: string,
    type: 'ticker' | 'orderbook' | 'trades' | 'ohlcv',
    callback: TickerCallback | OrderbookCallback | TradeCallback | OHLCVCallback,
  ): AdapterSubscription {
    const id = createSubscriptionId('raydium', type, symbol);
    const tokenAddress = this.extractTokenAddress(symbol);
    const sub: ActiveSubscription = { id, symbol, tokenAddress, type, callback };
    this.subscriptions.set(id, sub);

    return {
      id,
      symbol,
      type,
      dispose: () => { this.subscriptions.delete(id); },
    };
  }

  private async pollSubscriptions(): Promise<void> {
    const tradeSubscriptions = Array.from(this.subscriptions.values()).filter(s => s.type === 'trades');
    for (const sub of tradeSubscriptions) {
      const trades = await this.getRecentTrades(sub.symbol, 10);
      for (const trade of trades) {
        (sub.callback as TradeCallback)(trade);
      }
    }
  }

  private async fetchBirdeye<T>(url: string): Promise<BirdeyeResponse<T>> {
    const headers: Record<string, string> = { 'Content-Type': 'application/json' };
    if (this.birdeyeApiKey) {
      headers['X-API-KEY'] = this.birdeyeApiKey;
    }

    const response = await fetch(url, { headers });
    if (!response.ok) {
      throw new Error(`Birdeye API error: ${response.status} ${response.statusText}`);
    }

    return response.json() as Promise<BirdeyeResponse<T>>;
  }

  private extractTokenAddress(symbol: string): string {
    // If the symbol looks like a Solana address (base58, 32-44 chars), use directly
    if (/^[1-9A-HJ-NP-Za-km-z]{32,44}$/.test(symbol)) return symbol;
    // Otherwise, this is a normalized symbol -- address must be resolved via getSymbols()
    return symbol;
  }

  private updateState(state: ConnectionStatus['state'], errorMessage?: string): void {
    this.connectionState = {
      state,
      latencyMs: this.connectionState.latencyMs,
      messagesPerSecond: this.connectionState.messagesPerSecond,
      lastMessageAt: this.connectionState.lastMessageAt,
      errorMessage,
      reconnectAttempt: 0,
      uptime: this.getUptime(),
    };
    for (const callback of this.statusCallbacks.values()) {
      callback(this.connectionState);
    }
  }

  private getUptime(): number {
    if (this.connectTime === 0) return 0;
    return (Date.now() - this.connectTime) / 1000;
  }
}
